/* Barrel export for TextShuffle component family */

export { TextShuffle } from "./TextShuffle";
export type { TextShuffleProps, TextShuffleRef, TextShuffleVariant, TextAlign, ShuffleVariantConfig } from "./types";
export { useShuffleCycle } from "./hooks/useShuffleCycle";
export { useShuffleVariants, createCharacterItemVariants } from "./hooks/useShuffleVariants";
export { AnimatedWord } from "./AnimatedWord";
export { splitCharacters, hasRTL } from "./utils/splitCharacters";
export { DEFAULT_DURATION, DEFAULT_TRANSITION, SPRING_CONFIG, ELASTIC_SPRING, SNAPPY_SPRING, FLIP_TRANSITION } from "./utils/timing";

"use client";

import React, {
  useImperativeHandle,
  forwardRef,
  useState,
} from "react";
import { AnimatePresence } from "framer-motion";
import { TextShuffleProps, TextShuffleRef } from "./types";
import { useShuffleCycle } from "./hooks/useShuffleCycle";
import { AnimatedWord } from "./AnimatedWord";
import { DEFAULT_DURATION, DEFAULT_TRANSITION } from "./utils/timing";

/* ── Component ─────────────────────────────────────────────────── */

export const TextShuffle = forwardRef<TextShuffleRef, TextShuffleProps>(
  function TextShuffle(
    {
      words,
      duration = DEFAULT_DURATION,
      transition = DEFAULT_TRANSITION,
      loop = true,
      variant = "scramble",
      fontSize,
      fontWeight,
      align = "center",
      className,
      onWordChange,
      pauseOnHover = false,
      cursorBlink = false,
      gradient,
      outline,
      letterSpacing,
      lineHeight,
      uppercase,
      lowercase,
      style,
    },
    ref
  ) {
    /* cycle control */
    const {
      currentIndex,
      next,
      previous,
      goTo,
      play,
      pause,
    } = useShuffleCycle({
      words,
      duration,
      loop,
      onWordChange,
    });

    /* reduced motion */
    const [reducedMotion, setReducedMotion] = useState(false);
    React.useEffect(() => {
      const mql = window.matchMedia("(prefers-reduced-motion: reduce)");
      setReducedMotion(mql.matches);
      const handler = (e: MediaQueryListEvent) => setReducedMotion(e.matches);
      mql.addEventListener("change", handler);
      return () => mql.removeEventListener("change", handler);
    }, []);

    /* imperatives */
    useImperativeHandle(ref, () => ({
      next,
      previous,
      goTo,
      play,
      pause,
    }));

    /* current word */
    const currentWord = words[currentIndex] ?? "";

    /* computed wrapper style */
    const wrapperStyle: React.CSSProperties = {
      display: "inline-flex",
      alignItems: "center",
      justifyContent: align,
      fontSize,
      fontWeight,
      textAlign: align,
      ...style,
    };

    const handleMouseEnter = () => {
      if (pauseOnHover) pause();
    };

    const handleMouseLeave = () => {
      if (pauseOnHover) play();
    };

    return (
      <span
        className={className}
        style={wrapperStyle}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        aria-label={`Animated text showing ${currentWord}`}
        aria-live="polite"
        aria-atomic="true"
      >
        <span
          style={{
            display: "inline-flex",
            alignItems: "center",
            justifyContent: align,
          }}
        >
          <AnimatePresence mode="wait">
            <AnimatedWord
              key={currentIndex}
              word={currentWord}
              variant={variant}
              transitionDuration={reducedMotion ? 150 : transition}
              reducedMotion={reducedMotion}
              gradient={gradient}
              outline={outline}
              letterSpacing={letterSpacing}
              lineHeight={lineHeight}
              uppercase={uppercase}
              lowercase={lowercase}
            />
          </AnimatePresence>
        </span>

        {cursorBlink && (
          <span
            aria-hidden="true"
            style={{
              display: "inline-block",
              width: "0.6em",
              height: "1em",
              marginLeft: "0.15em",
              backgroundColor: "currentColor",
              verticalAlign: "middle",
              animation: "text-shuffle-blink 1s step-end infinite",
            }}
          >
            <style>{`
              @keyframes text-shuffle-blink {
                0%, 100% { opacity: 1; }
                50% { opacity: 0; }
              }
            `}</style>
          </span>
        )}
      </span>
    );
  }
);

export default TextShuffle;

"use client";

import React, { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { TextShuffleVariant } from "./types";
import { splitCharacters } from "./utils/splitCharacters";
import { createCharacterItemVariants, useShuffleVariants } from "./hooks/useShuffleVariants";

/* ── Types ──────────────────────────────────────────────────────── */

interface AnimatedWordProps {
  word: string;
  variant: TextShuffleVariant;
  transitionDuration: number;
  reducedMotion: boolean;
  gradient?: string;
  outline?: boolean;
  letterSpacing?: string;
  lineHeight?: string;
  uppercase?: boolean;
  lowercase?: boolean;
}

/* ── Scramble helper ───────────────────────────────────────────── */

function useScrambleText(target: string, duration: number, reducedMotion: boolean) {
  const [display, setDisplay] = useState(target);
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*";

  useEffect(() => {
    if (reducedMotion) {
      setDisplay(target);
      return;
    }

    const targetChars = splitCharacters(target);
    let current = targetChars.map(() => chars[Math.floor(Math.random() * chars.length)]).join("");
    setDisplay(current);

    const totalSteps = targetChars.length;
    const lockTimes = targetChars.map((_, i) => {
      const t = (i / Math.max(totalSteps - 1, 1)) * 0.6 + 0.2;
      return t;
    });
    const locks = Array(totalSteps).fill(false);

    let raf: number;
    const start = performance.now();
    const dur = duration;

    const tick = (now: number) => {
      const elapsed = now - start;
      const progress = Math.min(elapsed / dur, 1);

      const out = targetChars.map((c, i) => {
        if (locks[i]) return c;
        if (progress >= lockTimes[i]) {
          locks[i] = true;
          return c;
        }
        return chars[Math.floor(Math.random() * chars.length)];
      }).join("");

      setDisplay(out);

      if (progress < 1) {
        raf = requestAnimationFrame(tick);
      }
    };

    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [target, duration, reducedMotion]);

  return display;
}

/* ── Component ─────────────────────────────────────────────────── */

export const AnimatedWord = React.memo(function AnimatedWord({
  word,
  variant,
  transitionDuration,
  reducedMotion,
  gradient,
  outline,
  letterSpacing,
  lineHeight,
  uppercase,
  lowercase,
}: AnimatedWordProps) {
  const containerVariants = useShuffleVariants(variant, transitionDuration);
  const itemVariants = createCharacterItemVariants(variant);
  const characters = splitCharacters(word);
  const scrambled = useScrambleText(word, reducedMotion ? 150 : transitionDuration, reducedMotion);

  const textStyle: React.CSSProperties = {
    backgroundImage: gradient,
    WebkitBackgroundClip: gradient ? "text" : undefined,
    WebkitTextFillColor: gradient ? "transparent" : undefined,
    letterSpacing,
    lineHeight,
    textTransform: uppercase ? "uppercase" : lowercase ? "lowercase" : undefined,
  };

  /* outline stroke */
  if (outline) {
    textStyle.WebkitTextStrokeWidth = "1px";
    textStyle.WebkitTextStrokeColor = "currentColor";
    textStyle.WebkitTextFillColor = gradient ? undefined : "transparent";
  }

  /* scramble: matrix-style decode ───────────────────────── */
  if (variant === "scramble") {

    return (
      <motion.span
        variants={containerVariants}
        initial="initial"
        animate="animate"
        exit="exit"
        className={outline ? "text-shuffle-outline" : ""}
        style={textStyle}
      >
        {scrambled.split("").map((char, i) => (
          <span key={i} style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : undefined }}>
            {char || "\u00A0"}
          </span>
        ))}
      </motion.span>
    );
  }

  /* wave / glitch: per-character motion ─────────────────── */
  if (variant === "wave" || variant === "glitch") {
    return (
      <motion.span
        variants={containerVariants}
        initial="initial"
        animate="animate"
        exit="exit"
        className={outline ? "text-shuffle-outline" : ""}
        style={textStyle}
      >
        {characters.map((char, i) => (
          <motion.span
            key={i}
            variants={itemVariants}
            style={{ display: "inline-block", whiteSpace: char === " " ? "pre" : undefined }}
          >
            {char || "\u00A0"}
          </motion.span>
        ))}
      </motion.span>
    );
  }

  /* elastic / flipIn / blurReveal: whole-word motion ─────── */
  return (
    <motion.span
      variants={containerVariants}
      initial="initial"
      animate="animate"
      exit="exit"
      className={outline ? "text-shuffle-outline" : ""}
      style={{
        ...textStyle,
        display: "inline-block",
        transformStyle: variant === "flipIn" ? "preserve-3d" as React.CSSProperties["transformStyle"] : undefined,
      }}
    >
      {word}
    </motion.span>
  );
});

export type TextShuffleVariant =
  | "scramble"
  | "wave"
  | "glitch"
  | "elastic"
  | "flipIn"
  | "blurReveal";

export type TextAlign = "left" | "center" | "right";

export interface TextShuffleProps {
  /** Array of words to cycle through */
  words: string[];
  /** Duration a word is displayed before transitioning (ms). Default: 2200 */
  duration?: number;
  /** Transition duration between words (ms). Default: 700 */
  transition?: number;
  /** Whether to loop infinitely. Default: true */
  loop?: boolean;
  /** Visual morph variant. Default: "scramble" */
  variant?: TextShuffleVariant;
  /** Font size CSS value (e.g. "2rem", "32px") */
  fontSize?: string;
  /** Font weight (100-900) */
  fontWeight?: number;
  /** Text alignment. Default: "center" */
  align?: TextAlign;
  /** Additional CSS class names */
  className?: string;
  /** Callback when the active word changes */
  onWordChange?: (index: number) => void;
  /** Pause cycling on hover. Default: false */
  pauseOnHover?: boolean;
  /** Show a blinking cursor after the text. Default: false */
  cursorBlink?: boolean;
  /** CSS gradient value for text */
  gradient?: string;
  /** Render text with an outline stroke effect. Default: false */
  outline?: boolean;
  /** Letter spacing CSS value (e.g. "0.05em") */
  letterSpacing?: string;
  /** Line height CSS value (e.g. "1.2") */
  lineHeight?: string;
  /** Transform text to uppercase. Default: false */
  uppercase?: boolean;
  /** Transform text to lowercase. Default: false */
  lowercase?: boolean;
  /** Inline styles applied to the wrapper */
  style?: React.CSSProperties;
}

export interface TextShuffleRef {
  /** Advance to the next word */
  next: () => void;
  /** Go back to the previous word */
  previous: () => void;
  /** Pause automatic cycling */
  pause: () => void;
  /** Resume automatic cycling */
  play: () => void;
  /** Jump to a specific word by index */
  goTo: (index: number) => void;
}

export interface ShuffleVariantConfig {
  initial: Record<string, unknown>;
  animate: Record<string, unknown>;
  exit: Record<string, unknown>;
  transition: Record<string, unknown>;
}

import { useMemo } from "react";
import { Variants } from "framer-motion";
import { TextShuffleVariant } from "../types";
import {
  SPRING_CONFIG,
  ELASTIC_SPRING,
  FLIP_TRANSITION,
  SNAPPY_SPRING,
} from "../utils/timing";

/* ── Container-level variant factories ────────────────────────────── */

function createScrambleContainerVariants(transitionDuration: number): Variants {
  return {
    initial: { opacity: 0 },
    animate: {
      opacity: 1,
      transition: { duration: 0.05 },
    },
    exit: {
      opacity: 0,
      transition: { duration: Math.max(0.15, transitionDuration / 1000 / 3) },
    },
  };
}

function createWaveAndGlitchContainerVariants(transitionDuration: number): Variants {
  return {
    initial: {},
    animate: {
      transition: {
        staggerChildren: Math.min(0.05, transitionDuration / 1000 / 20),
        delayChildren: 0.03,
      },
    },
    exit: {
      transition: {
        staggerChildren: Math.min(0.03, transitionDuration / 1000 / 15),
        staggerDirection: -1,
        delayChildren: 0,
      },
    },
  };
}

function createElasticVariants(transitionDuration: number): Variants {
  return {
    initial: { opacity: 0, scale: 0.5, y: 30 },
    animate: {
      opacity: 1,
      scale: 1,
      y: 0,
      transition: { ...ELASTIC_SPRING, duration: transitionDuration / 1000 },
    },
    exit: {
      opacity: 0,
      scale: 0.8,
      y: -20,
      transition: { duration: (transitionDuration / 1000) * 0.5 },
    },
  };
}

function createFlipInVariants(transitionDuration: number): Variants {
  return {
    initial: { opacity: 0, rotateX: -90, transformPerspective: 800 },
    animate: {
      opacity: 1,
      rotateX: 0,
      transition: { ...FLIP_TRANSITION, duration: transitionDuration / 1000 },
    },
    exit: {
      opacity: 0,
      rotateX: 90,
      transition: { duration: (transitionDuration / 1000) * 0.5 },
    },
  };
}

function createBlurRevealVariants(transitionDuration: number): Variants {
  return {
    initial: { opacity: 0, scale: 1.1, filter: "blur(12px)" },
    animate: {
      opacity: 1,
      scale: 1,
      filter: "blur(0px)",
      transition: { ...SPRING_CONFIG, duration: transitionDuration / 1000 },
    },
    exit: {
      opacity: 0,
      scale: 0.95,
      filter: "blur(8px)",
      transition: { duration: (transitionDuration / 1000) * 0.5 },
    },
  };
}

/* ── Character-item variant factories ───────────────────────────── */

export function createCharacterItemVariants(variant: TextShuffleVariant): Variants {
  switch (variant) {
    case "wave":
      return {
        initial: { opacity: 0, y: 20, scale: 0.8 },
        animate: {
          opacity: 1,
          y: 0,
          scale: 1,
          transition: { ...SPRING_CONFIG, duration: 0.4 },
        },
        exit: {
          opacity: 0,
          y: -15,
          scale: 0.9,
          transition: { ...SNAPPY_SPRING, duration: 0.25 },
        },
      };
    case "glitch":
      return {
        initial: { opacity: 0, x: -4, skewX: "12deg" },
        animate: {
          opacity: 1,
          x: 0,
          skewX: "0deg",
          transition: { duration: 0.15, type: "spring", stiffness: 400, damping: 25 },
        },
        exit: {
          opacity: 0,
          x: 4,
          skewX: "-12deg",
          transition: { duration: 0.1 },
        },
      };
    default:
      return {
        initial: { opacity: 0, y: 10 },
        animate: {
          opacity: 1,
          y: 0,
          transition: { ...SPRING_CONFIG, duration: 0.3 },
        },
        exit: {
          opacity: 0,
          y: -10,
          transition: { duration: 0.2 },
        },
      };
  }
}

/* ── Hook ────────────────────────────────────────────────────────── */

export function useShuffleVariants(
  variant: TextShuffleVariant,
  transitionDuration: number
): Variants {
  return useMemo(() => {
    switch (variant) {
      case "wave":
      case "glitch":
        return createWaveAndGlitchContainerVariants(transitionDuration);
      case "scramble":
        return createScrambleContainerVariants(transitionDuration);
      case "elastic":
        return createElasticVariants(transitionDuration);
      case "flipIn":
        return createFlipInVariants(transitionDuration);
      case "blurReveal":
      default:
        return createBlurRevealVariants(transitionDuration);
    }
  }, [variant, transitionDuration]);
}

/* Manages cycling through an array of words with play/pause/goTo control. */

import { useState, useRef, useEffect, useCallback } from "react";

export interface UseShuffleCycleOptions {
  words: string[];
  duration: number;
  loop: boolean;
  onWordChange?: (index: number) => void;
}

export interface UseShuffleCycleReturn {
  currentIndex: number;
  isPaused: boolean;
  next: () => void;
  previous: () => void;
  goTo: (index: number) => void;
  play: () => void;
  pause: () => void;
}

export function useShuffleCycle({
  words,
  duration,
  loop,
  onWordChange,
}: UseShuffleCycleOptions): UseShuffleCycleReturn {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const indexRef = useRef(0);
  const pausedRef = useRef(false);

  const clearTimer = useCallback(() => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  }, []);

  const advance = useCallback(() => {
    if (!loop && indexRef.current >= words.length - 1) {
      return;
    }
    const nextIndex = loop
      ? (indexRef.current + 1) % words.length
      : Math.min(indexRef.current + 1, words.length - 1);

    setCurrentIndex(nextIndex);
    indexRef.current = nextIndex;
    onWordChange?.(nextIndex);
  }, [loop, words.length, onWordChange]);

  const scheduleNext = useCallback(() => {
    clearTimer();
    timerRef.current = setTimeout(() => {
      advance();
    }, duration);
  }, [duration, advance, clearTimer]);

  useEffect(() => {
    if (isPaused || words.length <= 1) {
      clearTimer();
      return;
    }
    scheduleNext();
    return () => clearTimer();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentIndex, isPaused, scheduleNext, clearTimer]);

  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.hidden) {
        pausedRef.current = isPaused;
        setIsPaused(true);
      } else {
        setIsPaused(pausedRef.current);
      }
    };
    document.addEventListener("visibilitychange", handleVisibilityChange);
    return () => {
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const next = useCallback(() => {
    clearTimer();
    if (!loop && indexRef.current >= words.length - 1) return;
    const nextIndex = loop
      ? (indexRef.current + 1) % words.length
      : Math.min(indexRef.current + 1, words.length - 1);
    setCurrentIndex(nextIndex);
    indexRef.current = nextIndex;
    onWordChange?.(nextIndex);
  }, [loop, words.length, onWordChange, clearTimer]);

  const previous = useCallback(() => {
    clearTimer();
    const prevIndex =
      indexRef.current === 0
        ? loop
          ? words.length - 1
          : 0
        : indexRef.current - 1;
    setCurrentIndex(prevIndex);
    indexRef.current = prevIndex;
    onWordChange?.(prevIndex);
  }, [loop, words.length, onWordChange, clearTimer]);

  const goTo = useCallback(
    (target: number) => {
      if (target < 0 || target >= words.length) return;
      clearTimer();
      setCurrentIndex(target);
      indexRef.current = target;
      onWordChange?.(target);
    },
    [words.length, onWordChange, clearTimer],
  );

  const play = useCallback(() => {
    setIsPaused(false);
  }, []);

  const pause = useCallback(() => {
    setIsPaused(true);
  }, []);

  return { currentIndex, isPaused, next, previous, goTo, play, pause };
}

/*
 * Splits a string into individual grapheme clusters using Intl.Segmenter when available.
 * Falls back to Array.from() for environments without Segmenter.
 */

/**
 * Split a string into grapheme clusters (individual user-perceived characters).
 * Handles complex scripts: Latin, Japanese, Chinese, Korean, Arabic, Hindi, emojis, and mixed scripts.
 */
export function splitCharacters(text: string): string[] {
  if (typeof text !== "string") return [];

  if (typeof Intl !== "undefined" && "Segmenter" in Intl) {
    try {
      const segmenter = new Intl.Segmenter("en", { granularity: "grapheme" });
      return Array.from(segmenter.segment(text)).map((s) => s.segment);
    } catch {
      // Fallback if Segmenter is unavailable or throws
    }
  }

  return Array.from(text);
}

/**
 * Checks if a string contains right-to-left (RTL) characters.
 * Useful for applying `dir="auto"` or `dir="rtl"`.
 */
export function hasRTL(text: string): boolean {
  return /[\u0591-\u07FF\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF\uFB50-\uFDFF\uFE70-\uFEFF]/.test(
    text,
  );
}

/* Timing and spring-physics constants for shuffle animations */

export const SPRING_CONFIG = {
  type: "spring" as const,
  stiffness: 170,
  damping: 22,
  mass: 0.8,
};

export const ELASTIC_SPRING = {
  type: "spring" as const,
  stiffness: 400,
  damping: 15,
  mass: 1.2,
};

export const SNAPPY_SPRING = {
  type: "spring" as const,
  stiffness: 300,
  damping: 30,
  mass: 0.5,
};

export const FLIP_TRANSITION = {
  type: "spring" as const,
  stiffness: 260,
  damping: 20,
};

export const DEFAULT_DURATION = 2200;
export const DEFAULT_TRANSITION = 700;
